211: const wildcard = "*"
212: 
213: func appendIfNotEmpty(s []string, v ...string) []string {
214: 	for _, vs := range v {
215: 		if vs != "" {
216: 			s = append(s, vs)
217: 		}
218: 	}
219: 
220: 	return s
221: }
